#ifndef GEMM_N6144_K4096_KERNEL_H_
#define GEMM_N6144_K4096_KERNEL_H_

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <stdint.h>

constexpr int GEMM_N = 6144;
constexpr int GEMM_K = 4096;

// C = A @ B^T
// A: [M,K] row-major FP16
// B: [N,K] row-major FP16
// C: [M,N] row-major FP16
void gemm_n6144_k4096_launch(const half* A,
                            const half* B,
                            half* C,
                            int M,
                            cudaStream_t stream);

#endif  // GEMM_N6144_K4096_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <stdint.h>

#include <mma.h>

using nvcuda::wmma::fragment;
using nvcuda::wmma::matrix_a;
using nvcuda::wmma::matrix_b;
using nvcuda::wmma::accumulator;

#define CUDA_CHECK_LAST_ERROR_NOEXCEPT() \
  do { (void)cudaGetLastError(); } while (0)

// Fixes vs previous version:
// 1) Reduce block size from 1024 threads (often problematic & slow) to 256 threads.
// 2) Reduce dynamic shared memory footprint drastically:
//    - No per-warp float shared "Cf" buffer; store wmma accumulator directly to a small per-warp half buffer in shared,
//      then each warp writes to global (coalesced-ish).
// 3) Keep A and B tiles in shared; transpose B tile into [BK, BN] so wmma can use row_major for B.
// 4) Use larger BK=128 to reduce number of k-iterations (4096/128=32 steps).
//
// Tile: BMxBN = 64x128, BK=128.
// Warps per block = (BM/16)*(BN/16)=4*8=32 warps => 1024 threads is too many;
// instead, we map only 8 warps (256 threads) to collaboratively load tiles and compute multiple warp-tiles per warp
// is complex, so we instead keep 32 warp-tiles but execute them over multiple "logical warps" using lane groups is not viable.
// Therefore: we change tiling to 64x64 per block => 16 warp tiles (4*4=16 warps) = 512 threads still high.
// Best practical: 32 warps with 256 threads isn't possible. So we instead choose BM=64 BN=64 giving 16 warps,
// and use 512 threads? still high. We'll use 256 threads and 8 warps by choosing BM=32 BN=64 => 8 warps.
// That means per-block output tile 32x64, still efficient and avoids huge launch/block issues.
//
// Final tile: BM=32, BN=64, BK=128. Warps/block=(32/16)*(64/16)=2*4=8 warps => 256 threads.
template <int BM, int BN, int BK>
__global__ __launch_bounds__(256, 2)
void gemm_wmma_sm80_kernel(const half* __restrict__ A,
                           const half* __restrict__ B,
                           half* __restrict__ C,
                           int M) {
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800)
  static_assert(BM % 16 == 0 && BN % 16 == 0 && BK % 16 == 0, "BM/BN/BK must be multiples of 16.");
  constexpr int WARP_SIZE = 32;
  constexpr int WARPS_M = BM / 16; // 2
  constexpr int WARPS_N = BN / 16; // 4
  constexpr int WARPS_PER_BLOCK = WARPS_M * WARPS_N; // 8

  const int tid = (int)threadIdx.x;
  const int warp_id = tid / WARP_SIZE;
  const int lane = tid & (WARP_SIZE - 1);
  if (warp_id >= WARPS_PER_BLOCK) return;

  const int block_m0 = (int)blockIdx.y * BM;
  const int block_n0 = (int)blockIdx.x * BN;

  const int warp_m = warp_id / WARPS_N;              // [0..1]
  const int warp_n = warp_id - warp_m * WARPS_N;     // [0..3]

  const int tile_m0 = block_m0 + warp_m * 16;
  const int tile_n0 = block_n0 + warp_n * 16;

  // Shared memory layout:
  // As:  BM * BK half
  // BsT: BK * BN half  (BsT[k,n] = B[n,k] for the current BN columns)
  // Ch:  WARPS_PER_BLOCK * (16*16) half  (per-warp output buffer)
  extern __shared__ __align__(16) unsigned char smem_raw[];
  half* As  = reinterpret_cast<half*>(smem_raw);
  half* BsT = As + (BM * BK);
  half* Ch  = BsT + (BK * BN);

  fragment<accumulator, 16, 16, 16, float> c_frag;
  nvcuda::wmma::fill_fragment(c_frag, 0.0f);

  // Iterate over K
#pragma unroll 1
  for (int k0 = 0; k0 < GEMM_K; k0 += BK) {
    // Cooperative load A tile [BM,BK]
    const int a_elems = BM * BK;
    for (int idx = tid; idx < a_elems; idx += (int)blockDim.x) {
      const int r = idx / BK;
      const int c = idx - r * BK;
      const int gm = block_m0 + r;
      const int gk = k0 + c;
      half v = __float2half_rn(0.0f);
      if (gm < M) v = A[gm * GEMM_K + gk];
      As[r * BK + c] = v;
    }

    // Cooperative load B tile [BN,BK] and transpose into BsT[k,n]
    const int b_elems = BK * BN;
    for (int idx = tid; idx < b_elems; idx += (int)blockDim.x) {
      const int k = idx / BN;
      const int n = idx - k * BN;
      const int gk = k0 + k;
      const int gn = block_n0 + n;
      half v = __float2half_rn(0.0f);
      if (gn < GEMM_N) v = B[gn * GEMM_K + gk];
      BsT[k * BN + n] = v;
    }

    __syncthreads();

#pragma unroll
    for (int kk = 0; kk < BK; kk += 16) {
      fragment<matrix_a, 16, 16, 16, half, nvcuda::wmma::row_major> a_frag;
      fragment<matrix_b, 16, 16, 16, half, nvcuda::wmma::row_major> b_frag;

      const half* a_ptr = As + (warp_m * 16) * BK + kk;        // lda = BK
      const half* b_ptr = BsT + kk * BN + (warp_n * 16);       // ldb = BN

      nvcuda::wmma::load_matrix_sync(a_frag, a_ptr, BK);
      nvcuda::wmma::load_matrix_sync(b_frag, b_ptr, BN);
      nvcuda::wmma::mma_sync(c_frag, a_frag, b_frag, c_frag);
    }

    __syncthreads();
  }

  // Store accumulator to shared half buffer, then each warp writes to global.
  half* c_warp_h = Ch + warp_id * 256;
  nvcuda::wmma::store_matrix_sync(c_warp_h, c_frag, 16, nvcuda::wmma::mem_row_major);

  // No need for __syncwarp: store_matrix_sync is warp-synchronous; then each lane reads distinct indices.
  for (int i = lane; i < 256; i += WARP_SIZE) {
    const int r = i >> 4;
    const int c = i & 15;
    const int gm = tile_m0 + r;
    const int gn = tile_n0 + c;
    if (gm < M && gn < GEMM_N) {
      C[gm * GEMM_N + gn] = c_warp_h[i];
    }
  }
#else
  (void)A; (void)B; (void)C; (void)M;
#endif
}

void gemm_n6144_k4096_launch(const half* A,
                            const half* B,
                            half* C,
                            int M,
                            cudaStream_t stream) {
  // Tuned for SM80 (A800): moderate block size, manageable shared memory.
  constexpr int BM = 32;
  constexpr int BN = 64;
  constexpr int BK = 128;

  constexpr int THREADS = 256;
  constexpr int WARPS_PER_BLOCK = (BM / 16) * (BN / 16); // 8

  dim3 block(THREADS, 1, 1);
  dim3 grid((GEMM_N + BN - 1) / BN, (M + BM - 1) / BM, 1);

  // Shared memory bytes:
  // As:  BM*BK half
  // BsT: BK*BN half
  // Ch:  WARPS_PER_BLOCK*256 half
  size_t shmem_bytes =
      (size_t)(BM * BK + BK * BN + WARPS_PER_BLOCK * 256) * sizeof(half);

  // Request larger dynamic shared if needed (safe to ignore error here; checked after launch)
  (void)cudaFuncSetAttribute(
      gemm_wmma_sm80_kernel<BM, BN, BK>,
      cudaFuncAttributeMaxDynamicSharedMemorySize,
      (int)shmem_bytes);

  gemm_wmma_sm80_kernel<BM, BN, BK><<<grid, block, shmem_bytes, stream>>>(A, B, C, M);
  CUDA_CHECK_LAST_ERROR_NOEXCEPT();
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cuda.h>
#include <cuda_runtime.h>

#include "kernel.h"

static void check_cuda(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK(t.device().is_cuda(), name, " must be a CUDA tensor");
}
static void check_contig(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.is_contiguous(), name, " must be contiguous");
}
static void check_fp16(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.dtype() == torch::kFloat16, name, " must be float16");
}

static torch::Tensor run_impl(torch::Tensor A, torch::Tensor B) {
  check_cuda(A, "A");
  check_cuda(B, "B");
  check_contig(A, "A");
  check_contig(B, "B");
  check_fp16(A, "A");
  check_fp16(B, "B");

  TORCH_CHECK(A.dim() == 2, "A must be rank-2 [M, K]");
  TORCH_CHECK(B.dim() == 2, "B must be rank-2 [N, K]");

  const int64_t M64 = A.size(0);
  const int64_t K_a = A.size(1);
  const int64_t N64 = B.size(0);
  const int64_t K_b = B.size(1);

  TORCH_CHECK(K_a == GEMM_K, "A.size(1) must be ", GEMM_K, ", got ", K_a);
  TORCH_CHECK(K_b == GEMM_K, "B.size(1) must be ", GEMM_K, ", got ", K_b);
  TORCH_CHECK(N64 == GEMM_N, "B.size(0) must be ", GEMM_N, ", got ", N64);
  TORCH_CHECK(M64 >= 0, "M must be non-negative");
  TORCH_CHECK(M64 <= INT32_MAX, "M too large for int32 indexing, got ", M64);

  auto C = torch::empty({M64, (int64_t)GEMM_N},
                        torch::TensorOptions().device(A.device()).dtype(torch::kFloat16));

  const half* A_ptr = reinterpret_cast<const half*>(A.data_ptr<at::Half>());
  const half* B_ptr = reinterpret_cast<const half*>(B.data_ptr<at::Half>());
  half* C_ptr = reinterpret_cast<half*>(C.data_ptr<at::Half>());

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();
  gemm_n6144_k4096_launch(A_ptr, B_ptr, C_ptr, (int)M64, stream);

  cudaError_t err = cudaGetLastError();
  TORCH_CHECK(err == cudaSuccess, "CUDA launch failed: ", cudaGetErrorString(err));

  // Sync for correctness in benchmark harnesses / eager execution
  err = cudaStreamSynchronize(stream);
  TORCH_CHECK(err == cudaSuccess, "cudaStreamSynchronize failed: ", cudaGetErrorString(err));

  return C;
}

// kwargs-capable wrapper: accepts (A,B) positionally or by name.
torch::Tensor run(pybind11::args args, pybind11::kwargs kwargs) {
  torch::Tensor A, B;
  if (args.size() == 2) {
    A = args[0].cast<torch::Tensor>();
    B = args[1].cast<torch::Tensor>();
  } else {
    TORCH_CHECK(kwargs.contains("A") && kwargs.contains("B"),
                "Expected arguments (A, B) either positionally or as kwargs");
    A = kwargs["A"].cast<torch::Tensor>();
    B = kwargs["B"].cast<torch::Tensor>();
  }
  return run_impl(A, B);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "gemm_n6144_k4096 (CUDA): C = A @ B.T (FP16 WMMA)");
}
